   324→                    fontWeight: isToday(date) ? 700 : 400,
   325→                    color: isToday(date) ? '#2563eb' : '#5c7080',
   326→                  }}
   327→                >
   328→                  <div style={{ fontWeight: 500 }}>{dayName}</div>
   329→                  <div>{dayNum}</div>
   330→                </div>
   331→              );
   332→            })}
