   345→                  <div className="train-id" style={{ fontWeight: 600, color: '#182026' }}>{train.trainId}</div>
   346→                  <div style={{ fontSize: 12, color: '#5c7080' }}>
   347→                    {train.fleetName} • {train.depotCode}
   348→                  </div>
   349→                </div>
   350→
   351→                {/* Date Cells */}
   352→                {dates.map((date) => {
   353→                  const dateStr = date.toISOString().split('T')[0];
   354→                  const event = train.events.find((e) => e.startDate === dateStr);
   355→                  const isWeekend = date.getDay() === 0 || date.getDay() === 6;
   356→                  const zoneKey = `${train.trainId}-${dateStr}`;
   357→                  const isValidDrop = validDropZones.has(zoneKey);
   358→                  const isInvalidDrop = draggingEvent && !isValidDrop && draggingEvent.trainId === train.trainId;
   359→
   360→                  return (
   361→                    <div
   362→                      key={`${train.id}-${dateStr}`}
   363→                      style={{
   364→                        width: 56,
   365→                        height: 48,
   366→                        flexShrink: 0,
   367→                        borderRight: '1px solid #f0f0f0',
   368→                        position: 'relative',
   369→                        backgroundColor: draggingEvent && isValidDrop ? '#d1fae5' : isToday(date) ? '#eff6ff' : isWeekend ? '#f9fafb' : 'transparent',
   370→                        outline: draggingEvent && isValidDrop ? '2px solid #10b981' : isInvalidDrop ? '2px solid #ef4444' : 'none',
   371→                        outlineOffset: -2,
   372→                      }}
   373→                      onDragOver={(e) => handleDragOver(train.trainId, dateStr, e)}
   374→                      onDrop={(e) => handleDrop(train.trainId, dateStr, e)}
   375→                    >
