   386→                          onDragEnd={handleDragEnd}
   387→                          style={{
   388→                            position: 'absolute',
   389→                            top: 4,
   390→                            left: 4,
   391→                            right: 4,
   392→                            bottom: 4,
   393→                            borderRadius: 4,
   394→                            cursor: 'move',
   395→                            display: 'flex',
   396→                            alignItems: 'center',
   397→                            justifyContent: 'center',
   398→                            fontSize: 11,
   399→                            fontWeight: 600,
