'use client';

import React, { useState, useCallback, useEffect } from 'react';
import { Card, Elevation, Spinner, Callout, Intent, Button, Tag, Dialog, DialogBody, DialogFooter } from '@blueprintjs/core';
import { apiFetch } from '@/lib/api';

interface DepotWeek {
  depotId: string;
  depotName: string;
  depotCode: string;
  week: string;
  weekStart: string;
  weekEnd: string;
  scheduled: number;
  capacity: number;
  utilization: number;
  trains: string[];
}

interface CapacityData {
  depots: {
    id: string;
    name: string;
    code: string;
    maxCapacity: number;
  }[];
  weeks: {
    week: string;
    start: string;
    end: string;
  }[];
  data: DepotWeek[];
}

/**
 * Depot Capacity Heatmap Component
 *
 * Shows weekly depot maintenance capacity utilization.
 * Color-coded: green (<70%), yellow (70-90%), red (>90%)
 */
export function DepotCapacityHeatmap() {
  const [capacityData, setCapacityData] = useState<CapacityData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedCell, setSelectedCell] = useState<DepotWeek | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    const { data, error } = await apiFetch<CapacityData>('/api/maintenance/depot-capacity');

    if (error) {
      setError(error);
    } else if (data) {
      setCapacityData(data);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const getUtilizationStyle = (utilization: number): React.CSSProperties => {
    if (utilization >= 100) return { backgroundColor: '#ef4444', color: '#ffffff' };
    if (utilization >= 90) return { backgroundColor: '#f87171', color: '#ffffff' };
    if (utilization >= 70) return { backgroundColor: '#fbbf24', color: '#1f2937' };
    if (utilization >= 50) return { backgroundColor: '#bbf7d0', color: '#1f2937' };
    if (utilization > 0) return { backgroundColor: '#dcfce7', color: '#1f2937' };
    return { backgroundColor: '#f9fafb', color: '#9ca3af' };
  };

  const getCellData = (depotId: string, week: string): DepotWeek | undefined => {
    return capacityData?.data.find((d) => d.depotId === depotId && d.week === week);
  };

  if (loading) {
    return (
      <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
        <Spinner size={32} />
        <p style={{ marginTop: 16, color: '#5c7080' }}>Loading depot capacity...</p>
      </Card>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error">
        {error}
      </Callout>
    );
  }

  if (!capacityData || capacityData.depots.length === 0) {
    return (
      <Card elevation={Elevation.ONE} style={{ padding: 32, textAlign: 'center', color: '#5c7080' }}>
        No depot capacity data available
      </Card>
    );
  }

  return (
    <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
      <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed' }}>
        <h2 style={{ margin: 0, fontSize: 18, fontWeight: 600, color: '#182026' }}>Depot Capacity per Week</h2>
        <p style={{ margin: '4px 0 0', fontSize: 14, color: '#5c7080' }}>
          Click a cell to see scheduled trains
        </p>
      </div>

      {/* Legend */}
      <div style={{ padding: '8px 16px', backgroundColor: '#f5f8fa', borderBottom: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', gap: 16, flexWrap: 'wrap' }}>
        <span style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Utilization:</span>
        <Tag style={{ backgroundColor: '#dcfce7', color: '#1f2937' }}>&lt;50%</Tag>
        <Tag style={{ backgroundColor: '#bbf7d0', color: '#1f2937' }}>50-70%</Tag>
        <Tag style={{ backgroundColor: '#fbbf24', color: '#1f2937' }}>70-90%</Tag>
        <Tag style={{ backgroundColor: '#f87171', color: '#ffffff' }}>&gt;90%</Tag>
        <Tag style={{ backgroundColor: '#ef4444', color: '#ffffff' }}>100%</Tag>
      </div>

      {/* Heatmap Grid */}
      <div style={{ overflowX: 'auto', padding: 16 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ padding: '8px 16px', textAlign: 'left', fontSize: 14, fontWeight: 500, color: '#5c7080', borderBottom: '1px solid #e1e8ed' }}>
                Depot
              </th>
              {capacityData.weeks.map((week) => (
                <th
                  key={week.week}
                  style={{ padding: '8px 16px', textAlign: 'center', fontSize: 14, fontWeight: 500, color: '#5c7080', borderBottom: '1px solid #e1e8ed' }}
                >
                  <div>{week.week}</div>
                  <div style={{ fontSize: 12, fontWeight: 400, color: '#8a9ba8' }}>
                    {new Date(week.start).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {capacityData.depots.map((depot) => (
              <tr key={depot.id}>
                <td style={{ padding: '12px 16px', borderBottom: '1px solid #f0f0f0' }}>
                  <div style={{ fontWeight: 500, color: '#182026' }}>{depot.name}</div>
                  <div style={{ fontSize: 12, color: '#5c7080' }}>
                    {depot.code} • Capacity: {depot.maxCapacity}/week
                  </div>
                </td>
                {capacityData.weeks.map((week) => {
                  const cellData = getCellData(depot.id, week.week);
                  const utilization = cellData?.utilization || 0;
                  const isAtCapacity = utilization >= 100;

                  return (
                    <td
                      key={`${depot.id}-${week.week}`}
                      style={{ padding: 8, borderBottom: '1px solid #f0f0f0', textAlign: 'center' }}
                    >
                      <button
                        onClick={() => cellData && setSelectedCell(cellData)}
                        disabled={!cellData || cellData.scheduled === 0}
                        style={{
                          width: '100%',
                          padding: '12px 8px',
                          borderRadius: 4,
                          border: 'none',
                          cursor: cellData && cellData.scheduled > 0 ? 'pointer' : 'default',
                          transition: 'all 0.2s',
                          ...getUtilizationStyle(utilization),
                        }}
                      >
                        <div style={{ fontSize: 14, fontWeight: 600 }}>
                          {cellData?.scheduled || 0}/{depot.maxCapacity}
                        </div>
                        <div style={{ fontSize: 12, opacity: 0.8 }}>
                          {utilization.toFixed(0)}%
                          {isAtCapacity && ' ⚠️'}
                        </div>
                      </button>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Selected Cell Details Modal */}
      <Dialog
        isOpen={!!selectedCell}
        onClose={() => setSelectedCell(null)}
        title={selectedCell ? `${selectedCell.depotName} - ${selectedCell.week}` : ''}
      >
        {selectedCell && (
          <>
            <DialogBody>
              <p style={{ fontSize: 14, color: '#5c7080', marginBottom: 16 }}>
                {new Date(selectedCell.weekStart).toLocaleDateString()} -{' '}
                {new Date(selectedCell.weekEnd).toLocaleDateString()}
              </p>

              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 14, color: '#5c7080' }}>Scheduled Maintenance</div>
                <div style={{ fontSize: 28, fontWeight: 700, color: '#182026' }}>
                  {selectedCell.scheduled} / {selectedCell.capacity}
                </div>
                <div style={{ fontSize: 14, color: selectedCell.utilization >= 90 ? '#dc2626' : '#5c7080' }}>
                  {selectedCell.utilization.toFixed(0)}% capacity used
                </div>
              </div>

              {selectedCell.trains.length > 0 && (
                <div>
                  <div style={{ fontSize: 14, fontWeight: 500, color: '#5c7080', marginBottom: 8 }}>
                    Trains Scheduled:
                  </div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                    {selectedCell.trains.map((train) => (
                      <Tag key={train} minimal style={{ fontFamily: 'monospace' }}>
                        {train}
                      </Tag>
                    ))}
                  </div>
                </div>
              )}

              {selectedCell.trains.length === 0 && (
                <p style={{ color: '#5c7080', fontSize: 14 }}>No trains scheduled</p>
              )}
            </DialogBody>
            <DialogFooter
              actions={
                <Button intent={Intent.PRIMARY} onClick={() => setSelectedCell(null)}>
                  Close
                </Button>
              }
            />
          </>
        )}
      </Dialog>
    </Card>
  );
}

