/**
 * MMS - Maintenance Routes
 *
 * Endpoints for maintenance schedule and Gantt chart data
 */

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { db, schema } from '../db/client';
import { eq, gte, lte, and, asc } from 'drizzle-orm';

interface ScheduleUpdateBody {
  startDate: string;
}

interface ScheduleIdParams {
  id: string;
}

export async function maintenanceRoutes(fastify: FastifyInstance) {
  /**
   * GET /api/maintenance/gantt
   * Returns maintenance schedule data for Gantt chart
   */
  fastify.get('/gantt', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      // Get date range (4 weeks from today)
      const startDate = new Date();
      startDate.setHours(0, 0, 0, 0);
      const endDate = new Date(startDate);
      endDate.setDate(endDate.getDate() + 28);

      const startDateStr = startDate.toISOString().split('T')[0];
      const endDateStr = endDate.toISOString().split('T')[0];

      // Get all trains with their relations
      const trainsData = await db.query.trains.findMany({
        with: {
          fleet: true,
          baseDepot: true,
        },
        limit: 50,
        orderBy: [asc(schema.trains.trainId)],
      });

      // Get maintenance schedules in range
      const schedules = await db.query.maintenanceSchedules.findMany({
        where: and(
          gte(schema.maintenanceSchedules.scheduledDate, startDateStr),
          lte(schema.maintenanceSchedules.scheduledDate, endDateStr)
        ),
        with: {
          depot: true,
        },
      });

      // Build train rows with events
      const trainRows = trainsData.map(train => ({
        id: train.id,
        trainId: train.trainId,
        fleetName: train.fleet?.name || 'Unknown',
        depotCode: train.baseDepot?.code || 'UNK',
        events: schedules
          .filter(s => s.trainId === train.id)
          .map(s => ({
            id: s.id,
            trainId: train.id,
            trainCode: train.trainId,
            type: s.maintenanceType as 'PM1' | 'PM2' | 'HM' | 'OVH',
            startDate: s.scheduledDate,
            endDate: s.scheduledDate,
            depotId: s.depotId,
            depotName: s.depot?.name || 'Unknown',
            kmAtMaintenance: train.currentKm || 0,
          })),
      }));

      return {
        trains: trainRows,
        startDate: startDateStr,
        endDate: endDateStr,
      };
    } catch (error) {
      request.log.error(error);
      return reply.status(500).send({ error: 'Failed to fetch gantt data' });
    }
  });

  /**
   * GET /api/maintenance/depot-capacity
   * Returns weekly depot capacity utilization
   */
  fastify.get('/depot-capacity', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      // Get all depots
      const depotsData = await db.query.depots.findMany({
        orderBy: [asc(schema.depots.code)],
      });

      // Generate 4 weeks of data
      const weeks: { week: string; start: string; end: string }[] = [];
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      for (let w = 0; w < 4; w++) {
        const weekStart = new Date(today);
        weekStart.setDate(today.getDate() + w * 7);
        const weekEnd = new Date(weekStart);
        weekEnd.setDate(weekStart.getDate() + 6);

        weeks.push({
          week: `Week ${w + 1}`,
          start: weekStart.toISOString().split('T')[0],
          end: weekEnd.toISOString().split('T')[0],
        });
      }

      // Get all maintenance schedules in range
      const allSchedules = await db.query.maintenanceSchedules.findMany({
        where: and(
          gte(schema.maintenanceSchedules.scheduledDate, weeks[0].start),
          lte(schema.maintenanceSchedules.scheduledDate, weeks[3].end)
        ),
        with: {
          train: true,
        },
      });

      // Build capacity data
      const capacityData: Array<{
        depotId: string;
        depotName: string;
        depotCode: string;
        week: string;
        weekStart: string;
        weekEnd: string;
        scheduled: number;
        capacity: number;
        utilization: number;
        trains: string[];
      }> = [];

      for (const depot of depotsData) {
        for (const week of weeks) {
          // Filter schedules for this depot in this week
          const weekSchedules = allSchedules.filter(s =>
            s.depotId === depot.id &&
            s.scheduledDate >= week.start &&
            s.scheduledDate <= week.end
          );

          // Get train codes
          const trainCodes = weekSchedules
            .map(s => s.train?.trainId || 'Unknown')
            .filter((v, i, a) => a.indexOf(v) === i); // unique

          // Capacity is simplified as max schedules per week
          const capacity = Math.ceil((depot.capacityManhours || 100) / 20);
          const utilization = capacity > 0 ? (weekSchedules.length / capacity) * 100 : 0;

          capacityData.push({
            depotId: depot.id,
            depotName: depot.name,
            depotCode: depot.code,
            week: week.week,
            weekStart: week.start,
            weekEnd: week.end,
            scheduled: weekSchedules.length,
            capacity,
            utilization: Math.round(utilization * 10) / 10,
            trains: trainCodes,
          });
        }
      }

      return {
        depots: depotsData.map(d => ({
          id: d.id,
          name: d.name,
          code: d.code,
          maxCapacity: Math.ceil((d.capacityManhours || 100) / 20),
        })),
        weeks,
        data: capacityData,
      };
    } catch (error) {
      request.log.error(error);
      return reply.status(500).send({ error: 'Failed to fetch depot capacity' });
    }
  });

  /**
   * PUT /api/maintenance/schedule/:id
   * Update a maintenance schedule (for drag-drop)
   */
  fastify.put<{ Params: ScheduleIdParams; Body: ScheduleUpdateBody }>(
    '/schedule/:id',
    async (request, reply) => {
      try {
        const { id } = request.params;
        const { startDate } = request.body;

        await db
          .update(schema.maintenanceSchedules)
          .set({ scheduledDate: startDate })
          .where(eq(schema.maintenanceSchedules.id, id));

        return { success: true, id, startDate };
      } catch (error) {
        request.log.error(error);
        return reply.status(500).send({ error: 'Failed to update schedule' });
      }
    }
  );
}

