/**
 * MMS - Metro Mileage Management System
 * Seed Data Generator
 *
 * Generates realistic demo data for Portuguese railway operations
 * Based on PRD specifications (2025-12-28)
 */

import postgres from 'postgres';

const connectionString = process.env.DATABASE_URL || 'postgresql://mms:mms@localhost:5432/mms';
const sql = postgres(connectionString);

// =============================================================================
// Data Definitions
// =============================================================================

const FLEETS = [
  { name: 'Metro Series 2200', manufacturer: 'Siemens', pm1: 15000, pm2: 45000, hm: 90000 },
  { name: 'Metro Series 2400', manufacturer: 'CAF', pm1: 18000, pm2: 54000, hm: 108000 },
  { name: 'Intercity Series 3400', manufacturer: 'Alstom', pm1: 20000, pm2: 60000, hm: 120000 },
  { name: 'Regional Series 3500', manufacturer: 'Stadler', pm1: 15000, pm2: 45000, hm: 90000 },
  { name: 'Urban Series 4000', manufacturer: 'Bombardier', pm1: 12000, pm2: 36000, hm: 72000 },
];

const DEPOTS = [
  { name: 'Lisboa - Santa Apolónia', code: 'LSA', lat: 38.7139, lon: -9.1227, tracks: 8, manhours: 160 },
  { name: 'Lisboa - Entrecampos', code: 'LEC', lat: 38.7472, lon: -9.1498, tracks: 6, manhours: 120 },
  { name: 'Porto - Campanhã', code: 'PRC', lat: 41.1496, lon: -8.5857, tracks: 10, manhours: 200 },
  { name: 'Porto - São Bento', code: 'PSB', lat: 41.1455, lon: -8.6108, tracks: 4, manhours: 80 },
  { name: 'Coimbra B', code: 'COI', lat: 40.2115, lon: -8.4356, tracks: 5, manhours: 100 },
  { name: 'Braga', code: 'BRG', lat: 41.5454, lon: -8.4265, tracks: 4, manhours: 80 },
  { name: 'Aveiro', code: 'AVE', lat: 40.6405, lon: -8.6538, tracks: 3, manhours: 60 },
  { name: 'Faro', code: 'FAR', lat: 37.0194, lon: -7.9322, tracks: 4, manhours: 80 },
  { name: 'Évora', code: 'EVO', lat: 38.5714, lon: -7.9092, tracks: 3, manhours: 60 },
  { name: 'Setúbal', code: 'SET', lat: 38.5244, lon: -8.8882, tracks: 4, manhours: 80 },
  { name: 'Guimarães', code: 'GUI', lat: 41.4433, lon: -8.2919, tracks: 3, manhours: 60 },
  { name: 'Viseu', code: 'VIS', lat: 40.6566, lon: -7.9124, tracks: 3, manhours: 60 },
  { name: 'Leiria', code: 'LEI', lat: 39.7436, lon: -8.8071, tracks: 3, manhours: 60 },
];

const TRAIN_PREFIXES = {
  'Metro Series 2200': 'UTE-2200',
  'Metro Series 2400': 'UTE-2400',
  'Intercity Series 3400': 'UTE-3400',
  'Regional Series 3500': 'UME-3500',
  'Urban Series 4000': 'UTE-4000',
};

const SERVICE_ROUTES = [
  // Intercity routes
  { code: 'IC', origin: 'Lisboa - Santa Apolónia', destination: 'Porto - Campanhã', distance: 336, type: 'intercity' },
  { code: 'IC', origin: 'Porto - Campanhã', destination: 'Lisboa - Santa Apolónia', distance: 336, type: 'intercity' },
  { code: 'IC', origin: 'Lisboa - Santa Apolónia', destination: 'Faro', distance: 309, type: 'intercity' },
  { code: 'IC', origin: 'Faro', destination: 'Lisboa - Santa Apolónia', distance: 309, type: 'intercity' },
  { code: 'IC', origin: 'Porto - Campanhã', destination: 'Braga', distance: 65, type: 'intercity' },
  { code: 'IC', origin: 'Braga', destination: 'Porto - Campanhã', distance: 65, type: 'intercity' },
  // Regional routes
  { code: 'R', origin: 'Lisboa - Entrecampos', destination: 'Coimbra B', distance: 199, type: 'regional' },
  { code: 'R', origin: 'Coimbra B', destination: 'Lisboa - Entrecampos', distance: 199, type: 'regional' },
  { code: 'R', origin: 'Porto - São Bento', destination: 'Aveiro', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Aveiro', destination: 'Porto - São Bento', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Lisboa - Santa Apolónia', destination: 'Setúbal', distance: 50, type: 'regional' },
  { code: 'R', origin: 'Setúbal', destination: 'Lisboa - Santa Apolónia', distance: 50, type: 'regional' },
  { code: 'R', origin: 'Porto - Campanhã', destination: 'Guimarães', distance: 60, type: 'regional' },
  { code: 'R', origin: 'Guimarães', destination: 'Porto - Campanhã', distance: 60, type: 'regional' },
  { code: 'R', origin: 'Coimbra B', destination: 'Leiria', distance: 75, type: 'regional' },
  { code: 'R', origin: 'Leiria', destination: 'Coimbra B', distance: 75, type: 'regional' },
  // Urban routes
  { code: 'U', origin: 'Lisboa - Entrecampos', destination: 'Lisboa - Santa Apolónia', distance: 5, type: 'regional' },
  { code: 'U', origin: 'Porto - Campanhã', destination: 'Porto - São Bento', distance: 3, type: 'regional' },
];

// =============================================================================
// Helper Functions
// =============================================================================

function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomFloat(min: number, max: number, decimals: number = 2): number {
  const value = Math.random() * (max - min) + min;
  return Number(value.toFixed(decimals));
}

function randomChoice<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

function formatTime(hours: number, minutes: number): string {
  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:00`;
}

function addMinutes(time: string, minutes: number): string {
  const [h, m] = time.split(':').map(Number);
  const totalMinutes = h * 60 + m + minutes;
  const newH = Math.floor(totalMinutes / 60) % 24;
  const newM = totalMinutes % 60;
  return formatTime(newH, newM);
}

// =============================================================================
// Seed Functions
// =============================================================================

async function seedFleets(): Promise<Map<string, string>> {
  console.log('Seeding fleets...');
  const fleetIds = new Map<string, string>();

  for (const fleet of FLEETS) {
    const result = await sql`
      INSERT INTO fleets (name, manufacturer, pm1_interval_km, pm2_interval_km, hm_interval_km)
      VALUES (${fleet.name}, ${fleet.manufacturer}, ${fleet.pm1}, ${fleet.pm2}, ${fleet.hm})
      RETURNING id
    `;
    fleetIds.set(fleet.name, result[0].id);
  }

  console.log(`  ✓ ${FLEETS.length} fleets created`);
  return fleetIds;
}

async function seedDepots(): Promise<Map<string, string>> {
  console.log('Seeding depots...');
  const depotIds = new Map<string, string>();

  for (const depot of DEPOTS) {
    const result = await sql`
      INSERT INTO depots (name, code, latitude, longitude, capacity_tracks, capacity_manhours)
      VALUES (${depot.name}, ${depot.code}, ${depot.lat}, ${depot.lon}, ${depot.tracks}, ${depot.manhours})
      RETURNING id
    `;
    depotIds.set(depot.name, result[0].id);
  }

  console.log(`  ✓ ${DEPOTS.length} depots created`);
  return depotIds;
}

async function seedTrains(
  fleetIds: Map<string, string>,
  depotIds: Map<string, string>
): Promise<string[]> {
  console.log('Seeding trains...');
  const trainIds: string[] = [];
  const trainsPerFleet = [25, 25, 20, 20, 20]; // ~110 trains total
  const depotNames = Array.from(depotIds.keys());
  const targetAvgKm = 180000; // Target average km

  let trainCount = 0;
  for (let i = 0; i < FLEETS.length; i++) {
    const fleet = FLEETS[i];
    const fleetId = fleetIds.get(fleet.name)!;
    const prefix = TRAIN_PREFIXES[fleet.name as keyof typeof TRAIN_PREFIXES];

    for (let j = 0; j < trainsPerFleet[i]; j++) {
      trainCount++;
      const trainNumber = trainCount.toString().padStart(3, '0');
      const trainId = `${prefix}-${trainNumber}`;

      // Create km variance: most within ±15%, some outliers at ±25%
      let kmVariance = randomFloat(-0.15, 0.15);
      if (trainCount % 12 === 0) {
        // ~8 outliers
        kmVariance = randomChoice([randomFloat(-0.30, -0.20), randomFloat(0.20, 0.30)]);
      }

      const currentKm = Math.round(targetAvgKm * (1 + kmVariance));
      const depot = randomChoice(depotNames);
      const depotData = DEPOTS.find(d => d.name === depot)!;

      // Randomize position slightly from depot
      const lat = depotData.lat + randomFloat(-0.05, 0.05, 6);
      const lon = depotData.lon + randomFloat(-0.05, 0.05, 6);

      // Random fitness (95% fit)
      const fitness = Math.random() > 0.05 ? 'fit' : 'unfit';

      // Next maintenance km
      const nextMaintenanceKm = currentKm + randomInt(1000, fleet.pm1);

      const result = await sql`
        INSERT INTO trains (
          train_id, fleet_id, base_depot_id, current_km, target_km,
          fitness_status, next_maintenance_km, latitude, longitude
        )
        VALUES (
          ${trainId}, ${fleetId}, ${depotIds.get(depot)!}, ${currentKm}, ${targetAvgKm},
          ${fitness}, ${nextMaintenanceKm}, ${lat}, ${lon}
        )
        RETURNING id
      `;
      trainIds.push(result[0].id);
    }
  }

  console.log(`  ✓ ${trainIds.length} trains created`);
  return trainIds;
}

async function seedServices(): Promise<string[]> {
  console.log('Seeding services...');
  const serviceIds: string[] = [];
  let serviceNumber = 100;

  // Create ~250 services
  const startHour = 5; // First train at 05:00
  const endHour = 23; // Last train at 23:00
  const interval = 30; // Minutes between services

  for (let hour = startHour; hour <= endHour; hour++) {
    for (let minute = 0; minute < 60; minute += interval) {
      // Pick a random route
      const route = randomChoice(SERVICE_ROUTES);
      serviceNumber++;

      const departureTime = formatTime(hour, minute);
      // Calculate arrival based on distance (average 100km/h for intercity, 60km/h for regional)
      const speed = route.type === 'intercity' ? 100 : 60;
      const travelMinutes = Math.round((route.distance / speed) * 60);
      const arrivalTime = addMinutes(departureTime, travelMinutes);

      const result = await sql`
        INSERT INTO services (
          service_code, origin, destination, distance_km, departure_time, arrival_time, service_type
        )
        VALUES (
          ${`${route.code} ${serviceNumber}`}, ${route.origin}, ${route.destination},
          ${route.distance}, ${departureTime}, ${arrivalTime}, ${route.type}
        )
        RETURNING id
      `;
      serviceIds.push(result[0].id);

      // Don't exceed 300 services
      if (serviceIds.length >= 280) break;
    }
    if (serviceIds.length >= 280) break;
  }

  console.log(`  ✓ ${serviceIds.length} services created`);
  return serviceIds;
}

async function seedMileageHistory(trainIds: string[]): Promise<void> {
  console.log('Seeding mileage history (6 months)...');
  const today = new Date();
  let recordCount = 0;

  for (const trainId of trainIds) {
    // Get train's current km
    const train = await sql`SELECT current_km FROM trains WHERE id = ${trainId}`;
    let currentKm = train[0].current_km;

    // Go back 180 days and build history
    for (let daysAgo = 180; daysAgo >= 0; daysAgo -= 7) {
      // Weekly mileage between 2000-4000 km
      const weeklyKm = randomInt(2000, 4000);
      const kmValue = Math.max(0, currentKm - (daysAgo / 7) * weeklyKm);

      const recordDate = new Date(today);
      recordDate.setDate(recordDate.getDate() - daysAgo);
      const dateStr = recordDate.toISOString().split('T')[0];

      await sql`
        INSERT INTO mileage_history (train_id, recorded_date, km_value)
        VALUES (${trainId}, ${dateStr}, ${Math.round(kmValue)})
      `;
      recordCount++;
    }
  }

  console.log(`  ✓ ${recordCount} mileage history records created`);
}

async function seedMaintenanceSchedules(
  trainIds: string[],
  depotIds: Map<string, string>
): Promise<void> {
  console.log('Seeding maintenance schedules...');
  const depotIdList = Array.from(depotIds.values());
  let scheduleCount = 0;
  const today = new Date();

  // Create some past completed maintenance and future scheduled
  for (const trainId of trainIds) {
    // 1-3 maintenance events per train
    const eventCount = randomInt(1, 3);

    for (let i = 0; i < eventCount; i++) {
      const maintenanceType = randomChoice(['PM1', 'PM1', 'PM1', 'PM2', 'HM']); // PM1 more common
      const daysOffset = randomInt(-60, 30); // Past 60 days to next 30 days
      const scheduleDate = new Date(today);
      scheduleDate.setDate(scheduleDate.getDate() + daysOffset);
      const dateStr = scheduleDate.toISOString().split('T')[0];

      const status = daysOffset < -5 ? 'completed' : daysOffset < 0 ? 'in_progress' : 'scheduled';
      const duration = maintenanceType === 'PM1' ? 1 : maintenanceType === 'PM2' ? 2 : 5;

      await sql`
        INSERT INTO maintenance_schedules (
          train_id, depot_id, maintenance_type, scheduled_date, duration_days, status
        )
        VALUES (
          ${trainId}, ${randomChoice(depotIdList)}, ${maintenanceType},
          ${dateStr}, ${duration}, ${status}
        )
      `;
      scheduleCount++;
    }
  }

  console.log(`  ✓ ${scheduleCount} maintenance schedules created`);
}

// =============================================================================
// Main Seed Function
// =============================================================================

async function seed() {
  console.log('\n🚂 MMS Demo Data Seeding\n');
  console.log('='.repeat(50));

  try {
    // Clear existing data
    console.log('\nClearing existing data...');
    await sql`TRUNCATE maintenance_schedules, mileage_history, allocations, services, trains, depots, fleets CASCADE`;
    console.log('  ✓ Tables cleared');

    // Seed in order
    const fleetIds = await seedFleets();
    const depotIds = await seedDepots();
    const trainIds = await seedTrains(fleetIds, depotIds);
    await seedServices();
    await seedMileageHistory(trainIds);
    await seedMaintenanceSchedules(trainIds, depotIds);

    console.log('\n' + '='.repeat(50));
    console.log('✅ Demo data seeding completed successfully!\n');

    // Print summary
    const stats = await sql`
      SELECT
        (SELECT COUNT(*) FROM fleets) as fleets,
        (SELECT COUNT(*) FROM depots) as depots,
        (SELECT COUNT(*) FROM trains) as trains,
        (SELECT COUNT(*) FROM services) as services,
        (SELECT COUNT(*) FROM mileage_history) as history,
        (SELECT COUNT(*) FROM maintenance_schedules) as schedules
    `;

    console.log('📊 Summary:');
    console.log(`   Fleets: ${stats[0].fleets}`);
    console.log(`   Depots: ${stats[0].depots}`);
    console.log(`   Trains: ${stats[0].trains}`);
    console.log(`   Services: ${stats[0].services}`);
    console.log(`   History records: ${stats[0].history}`);
    console.log(`   Maintenance schedules: ${stats[0].schedules}`);

    // Check km variance
    const variance = await sql`
      SELECT
        AVG(current_km) as avg_km,
        STDDEV(current_km) as stddev_km,
        MIN(current_km) as min_km,
        MAX(current_km) as max_km
      FROM trains
    `;
    const avgKm = Math.round(variance[0].avg_km);
    const variancePercent = ((variance[0].stddev_km / variance[0].avg_km) * 100).toFixed(1);
    console.log(`\n📈 Km Distribution:`);
    console.log(`   Average: ${avgKm.toLocaleString()} km`);
    console.log(`   Variance: ${variancePercent}%`);
    console.log(`   Range: ${Math.round(variance[0].min_km).toLocaleString()} - ${Math.round(variance[0].max_km).toLocaleString()} km`);

  } catch (error) {
    console.error('Seed failed:', error);
    process.exit(1);
  } finally {
    await sql.end();
  }
}

seed();

