### Correcao 3: Adicionar Validacao Robusta (Story 6-4)

**Modificar handleDragStart em MaintenanceGantt.tsx:**

```typescript
const handleDragStart = async (event: MaintenanceEvent, e: React.DragEvent) => {
  setDraggingEvent(event);
  e.dataTransfer.effectAllowed = 'move';

  // Buscar capacidade do depot para cada dia
  const { data: capacityData } = await apiFetch<CapacityData>('/api/maintenance/depot-capacity');

  const validZones = new Set<string>();
  dates.forEach((date) => {
    const dateStr = date.toISOString().split('T')[0];
    const isPast = date < new Date();
    const weekKey = getWeekKey(date);

    // Verificar capacidade do depot
    const depotCapacity = capacityData?.data.find(
      d => d.depotId === event.depotId && d.week === weekKey
    );
    const hasCapacity = !depotCapacity || depotCapacity.utilization < 100;

    if (!isPast && hasCapacity) {
      validZones.add(`${event.trainId}-${dateStr}`);
    }
  });
  setValidDropZones(validZones);
};
```

