### Correcao 4: Adicionar Endpoint de Validacao

**Novo endpoint em maintenance.ts:**

```typescript
fastify.post<{ Body: { trainId: string; depotId: string; date: string } }>(
  '/validate',
  async (request, reply) => {
    const { trainId, depotId, date } = request.body;

    const errors: string[] = [];

    // 1. Verificar se data nao e passado
    if (new Date(date) < new Date()) {
      errors.push('Cannot schedule maintenance in the past');
    }

    // 2. Verificar capacidade do depot
    const weekStart = getWeekStart(date);
    const schedulesInWeek = await db.query.maintenanceSchedules.findMany({
      where: and(
        eq(schema.maintenanceSchedules.depotId, depotId),
        gte(schema.maintenanceSchedules.scheduledDate, weekStart),
        lte(schema.maintenanceSchedules.scheduledDate, addDays(weekStart, 6))
      ),
    });

    const depot = await db.query.depots.findFirst({
      where: eq(schema.depots.id, depotId)
    });

    const capacity = Math.ceil((depot?.capacityManhours || 100) / 20);
    if (schedulesInWeek.length >= capacity) {
      errors.push(`Depot ${depot?.name} is at capacity for this week`);
    }

    // 3. Verificar conflito com outras manutencoes do mesmo trem
    const trainSchedules = await db.query.maintenanceSchedules.findMany({
      where: and(
        eq(schema.maintenanceSchedules.trainId, trainId),
        eq(schema.maintenanceSchedules.scheduledDate, date)
      ),
    });

    if (trainSchedules.length > 0) {
      errors.push('Train already has maintenance scheduled for this date');
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }
);
```

